class ListNode { constructor(val) { this.val=val; this.next=null; } }
class LinkedList {
  constructor() { this.head=new ListNode(-1); this.size=0; }
  get(i) {
    if(i<0||i>=this.size) return -1;
    let cur=this.head.next; for(let k=0;k<i;k++) cur=cur.next; return cur.val;
  }
  insertHead(v) { const n=new ListNode(v); n.next=this.head.next; this.head.next=n; this.size++; }
  insertTail(v) { let cur=this.head; while(cur.next) cur=cur.next; cur.next=new ListNode(v); this.size++; }
  remove(i) {
    if(i<0||i>=this.size) return false;
    let cur=this.head; for(let k=0;k<i;k++) cur=cur.next;
    cur.next=cur.next.next; this.size--; return true;
  }
}
